class n extends HTMLElement{constructor(){super(...arguments),this.updateActiveLink=()=>{const t=window.location.hash;this.querySelectorAll("a[data-link]").forEach(e=>{const a=e.getAttribute("href");a===t||a==="#"&&t===""?e.setAttribute("data-active",""):e.removeAttribute("data-active")})}}connectedCallback(){this.updateActiveLink(),window.addEventListener("hashchange",this.updateActiveLink)}disconnectedCallback(){window.removeEventListener("hashchange",this.updateActiveLink)}}customElements.get("rle-header")||customElements.define("rle-header",n);
